        end
        self._cityWallEffect = require("LApp.component.dp.LxEffectDp"):new()
        self._cityWallEffect:InitDp("fx_ui_chengqiang_baohu", self._buildingTrans)
        self._cityWallEffect:SetScale(1)
        self._cityWallEffect:SetLocalPosition(Vector3.zero)
        self._cityWallEffect:SetLoadedCallback(function(ef)
            self:CityWallEffectLoaded(ef)
        end)
        self._cityWallEffect:Load()

    end
end
