function LCityBuilding:CheckShow()
    if ((self._buildingObj == nil) or (self._cityView == nil)) then
        self._boxCollider.enabled = false
        return
    end
    local show = self._cityView._buildingMgr:GetBuildingShow(self._buildingRefId)
    if (show) then
        --显示建筑，隐藏树
        self._boxCollider.enabled = true
        ShowObject(self._bodyObj, true)
        ShowObject(self._defaultObj, false)
    else
        --隐藏建筑，显示树
        self._boxCollider.enabled = false
        ShowObject(self._bodyObj, false)
        ShowObject(self._defaultObj, true)
    end
    self:UpdateShow()
end
function LCityBuilding:SetBuildingObj(buildingTrans)
    self._buildingTrans = buildingTrans
    self._boxCollider = buildingTrans.gameObject:GetComponent(typeOfBoxCollider)
    self._bodyObj = FindChild(buildingTrans, "Body").gameObject
    self._defaultObj = FindChild(buildingTrans, "Default").gameObject
    if buildingTrans ~= nil then
        self._buildingObj = buildingTrans.gameObject
        self.spriteRenderer = FindChild(self._buildingTrans, "Body"):GetComponent(typeof(UnityEngine.SpriteRenderer))
    end
end
function LCityBuilding:GetPosition()
    if (self._buildingTrans == nil) then
        return Vector3.zero
    end
    return self._buildingTrans.position
end
