function LCityBuilding:StoryBuildDie()

    self._modelName = nil
    if(self._spineDp ~= nil)then
        self._spineDp:Dispose()
    end
end
function LCityBuilding:StoryBuildBirth(callBack)
    local levelData = self:GetLevelData()
    if(self._modelName == levelData.levelShow)then
        if(callBack ~= nil)then
            callBack();
        end
        self:SetPeopleNodeList()
        self:LoadedCallBack(self._spineDp)

        return
    end
    ShowObject(self._bodyObj,true)
    ShowObject(self._defaultObj,false)
    self._boxCollider.enabled = true
    self:SetImage(self.spriteRenderer, "")

    if(self._spineDp ~= nil)then
        self._spineDp:Dispose()
    end
    self._spineDp = require("LApp.component.dp.LxSpineDp"):new()
    self._modelName = levelData.levelShow
    self._spineDp:InitDp(levelData.levelShow,self.spriteRenderer.transform)
    self._spineDp:SetLocalPosition(Vector3(0,0,0))
    self._spineDp:SetScale(1)
    local defaultLayer = 5
    local layerOrder = checknumber(self._buildingRef.layer)
    if(layerOrder >= 0)then
        defaultLayer = layerOrder
    end
    self._spineDp:SetRenderOrder(defaultLayer)
    self._spineDp:SetLoadedCallback(function(dp)
        self:SetPeopleNodeList()
        self:LoadedCallBack(dp)
        if(callBack ~= nil)then
            callBack();
        end
    end)
    self._spineDp:Load()
end
function LCityBuilding:GetLevelData()
    self._buildingData = ModuleCenter.Building:GetBuildingInfo(self._buildingRefId)
    local buildLevel = 0;--默认未建造，0级
    if (self._buildingData ~= nil) then
        --已经建造
        buildLevel = self._buildingData.level;
    end
    local buildType = self._buildingRef.type;

    local refId = buildType * 1000 + buildLevel;
    local levelData = GameTable.BuildingLvRef[refId];
    return levelData
end

function LCityBuilding:PlayInView()

    if(self._buildingRef.showIn == 1)then
        if(self._inView)then
            return
        end
        local levelData = self:GetLevelData()
        if(levelData.level <= 0)then
            return
        end
        if(self._spineDp:ExistsAniName("inview"))then
            if(self._curPlayAniName == nil)then
                self._curPlayAniName = self._spineDp:GetCurAniName()
            end
            self:PlayAni("inview",true)
            self._inView = true

            local buildingObj = ModuleCenter.Building:GetBuildingInfo(self._buildingRefId)
            if(buildingObj)then
                for i, v in ipairs(buildingObj.workers) do
                    if(v > 0)then
                        local people = CtrlCenter.City:GetPeopleObj(v)
                        if(people)then
                            people:BuildInView()
                        end
                    end

                end
                if(self._dropHudList)then
                    for i, v in pairs(self._dropHudList) do
                        v:PlayInView()
                    end
                end
            end
        end
        self:LoadInViewSpine()
        self:RefreshInView()
    end

end
function LCityBuilding:PlayOutView()
    --self:PlayAni(self._curPlayAniName,true)
    if(self._inView == false or self._inView == nil)then
        return
    end
    if(self._curPlayAniName ~= nil)then
        --self:PlayAni(_aniEnums.idle1,true)

        self._inView = false
        if(self._curPlayAniName == "idle2" or self._curPlayAniName == "idle1")then
            local timeState = CtrlCenter.City:GetCurTimeState()
            if(timeState == 1 or timeState == 3)then
                self._curPlayAniName = "idle1"
                self:BuildRest()
            else
                self._curPlayAniName = "idle2"
                self:BuildWork()
            end
        else
            if(self._curPlayAniName == "inview")then
                self:SetBuildingAni()
            end
            --self:PlayAni(self._curPlayAniName,true)
        end

        self._curPlayAniName = nil
        local buildingObj = ModuleCenter.Building:GetBuildingInfo(self._buildingRefId)
        if(buildingObj)then
            for i, v in ipairs(buildingObj.workers) do
                if(v > 0)then
                    local people = CtrlCenter.City:GetPeopleObj(v)
                    if(people)then
                        people:BuildOutView()
                    end
                end
            end
            if(self._dropHudList)then
                for i, v in pairs(self._dropHudList) do
                    v:PlayOutView()
                end
            end
        end
    end
    self:RefreshInView()
end
function LCityBuilding:BuildWork()

    if(CtrlCenter.City:BuildIsInStory(self._buildingRefId))then
        return
    end

    if(self._dropHudList)then
        for i, v in pairs(self._dropHudList) do
            v:RefreshBuildingInfo()
        end
    end
    if(self._inView)then
        return
    end
    if(self._buildingRef.workSpine == 0)then
        self:SetBuildingAni()
        return
    end
    local buildObj = ModuleCenter.Building:GetBuildingInfo(self._buildingRefId)
    if(buildObj == nil)then
        self:SetBuildingAni()
        return
    end
    if(CtrlCenter.Building:CheckBuildHasWorker(self._buildingRefId) == false)then
        self:SetBuildingAni()
        return
    end


    if(self._spineDp:GetCurAniName() == "idle2")then
        return
    end
    self:PlayAni("idle2",true)
end
function LCityBuilding:BuildRest()
    if(self._dropHudList)then
        for i, v in pairs(self._dropHudList) do
            v:RefreshBuildingInfo()
        end
    end
    self:SetBuildingAni()

end
function LCityBuilding:LoadInViewSpine()
    if(checknumber(self._buildingRef.showIn) <= 0)then
        return
    end

    --副建筑
    local unLockInnerList = CtrlCenter.Building:GetInnerDepBuildings(self._buildingRefId)
    for key, build in pairs(unLockInnerList) do
        local cfg = GameTable.BuildingInRef[build]
        local innerData = CtrlCenter.Building:GetInnerBuildLvl(self._buildingRefId,BuildInnerPosition.InnerDep)
        if(innerData == nil or innerData == false)then
            return
        end
        local sideList = cfg.inSide
        for i, v in pairs(sideList) do
            local nodeName = string.split(v,"=")
            if(innerData.level >= checknumber(nodeName[2]))then
                if(self._spineDp == nil or self._spineDp:GetDpTrans() == nil or self._spineDp:IsDisposed())then
                    return
                end
                local trans = self._spineDp:GetDpTrans():Find(nodeName[1])
                if(trans == nil)then
                    if(LOG_INFO_ENABLED)then
                        print(self._spineDp:GetDpTrans().name,nodeName[1])
                    end
                    break
                end
                if(trans.childCount <= 0 and self._innerSpineList[nodeName[1]] == nil)then
                    local spineDp = require("LApp.component.dp.LxSpineDp"):new()
                    spineDp:InitDp(cfg.inSideSp,trans)
                    spineDp:SetLocalPosition(Vector3.zero)
                    spineDp:SetScale(1)
                    local order = checknumber(self._buildingRef.layer)
                    spineDp:SetRenderOrder(order + 1)
                    spineDp:SetLoadedCallback(function(dp)
                        if(self._inView)then
                            ShowObject(spineDp:GetDpGo(),true)
                        else
                            ShowObject(spineDp:GetDpGo(),false)
                        end
                    end)
                    spineDp:Load()
                    local data = {}
                    data.name = nodeName[1]
                    data.order = checknumber(nodeName[3])
                    table.insert(self._orderList,data)
                    self._innerSpineList[nodeName[1]] = spineDp
                    --table.insert(self._innerSpineList,spineDp)
                end
            end
        end
    end

    --主建筑
    local mainInnerCfg = CtrlCenter.Building:GetInnerMainBuilding(self._buildingRef.type)
    local mainInnerData = CtrlCenter.Building:GetInnerBuildLvl(self._buildingRefId,BuildInnerPosition.InnerMain)
    if(mainInnerData == false or mainInnerData == nil)then
        return
    end
    for i, v in pairs(mainInnerCfg.inSide) do
        local nodeInfo = string.split(v,"=")
        if(mainInnerData.level >= checknumber(nodeInfo[2]))then
            if(self._spineDp == nil or self._spineDp:GetDpTrans() == nil or self._spineDp:IsDisposed())then
                return
            end
            local trans = self._spineDp:GetDpTrans():Find(nodeInfo[1])
            if(trans == nil)then
                if(LOG_INFO_ENABLED)then
                    print(self._spineDp:GetDpTrans().name,nodeInfo[1])
                end
                break
            end
            if(trans.childCount <= 0 and self._innerSpineList[nodeInfo[1]] == nil)then
                local spineDp = require("LApp.component.dp.LxSpineDp"):new()
                spineDp:InitDp(mainInnerCfg.inSideSp,trans)
                spineDp:SetLocalPosition(Vector3.zero)
                spineDp:SetScale(1)
                local order = checknumber(self._buildingRef.layer)
                spineDp:SetRenderOrder(order + 1)
                spineDp:SetLoadedCallback(function(dp)
                    if(self._inView)then
                        ShowObject(spineDp:GetDpGo(),true)
                    else
                        ShowObject(spineDp:GetDpGo(),false)
                    end
                    if(self._buildingRef.workSpine > 0)then
                        local dropHud = require("LApp.gameplay.city.view.LCityBuildingDropHud"):new()
                        dropHud:InitHud(self._cityView._buildingMgr._dropHudObj,spineDp:GetDpTrans(),self._buildingRefId,i)
                        table.insert(self._dropHudList,dropHud)
                    end
                end)
                spineDp:Load()
                local data = {}
                data.name = nodeInfo[1]
                data.order = checknumber(nodeInfo[3])
                table.insert(self._orderList,data)
                self._innerSpineList[nodeInfo[1]] = spineDp
                --table.insert(self._innerSpineList,spineDp)
            end
        end
    end

    --小人用居民AI，但是挂点在建筑内
    table.sort(self._orderList, function(a,b)
        return a.order < b.order
    end)
end

function LCityBuilding:RefreshInView()
    if LOG_INFO_ENABLED then
        printError(self._orderList)
    end
    if(self._inView)then
        for i, v in pairs(self._innerSpineList) do
            v:SetRenderOrder(self:GetOrderByName(i))
            ShowObject(v:GetDpGo(),true)
        end
    else
        for i, v in pairs(self._innerSpineList) do
            ShowObject(v:GetDpGo(),false)
        end
    end
end
function LCityBuilding:GetOrderByName(nodeName)
    for i, v in pairs(self._orderList) do
        if(v.name == nodeName)then
            return self._buildingRef.layer + i * 20
        end
    end
end
function LCityBuilding:PlayAni(aniName, loop)

    if (self._spineDp) then
        self._spineDp:PlayAni(aniName, loop)
    end
end

function LCityBuilding:UpdateShow()
    local levelData = self:GetLevelData()
    if (checknumber(self._oldLevel) < checknumber(levelData.level)) then
        if (self._inited) then
            self:ShowLevelUpEffect()
        end
        self._oldLevel = levelData.level
    end
    self._inited = true
    self:SetImage(self.spriteRenderer, "")
    if (self._modelName == levelData.levelShow) then
        --self:SetBuildingAni()
        self:CheckWorkRestState()
        return
    end
    if (self._spineDp ~= nil) then
        self._spineDp:Dispose()
    end
    self._spineDp = require("LApp.component.dp.LxSpineDp"):new()
    self._modelName = levelData.levelShow
    self._spineDp:InitDp(levelData.levelShow, self.spriteRenderer.transform)
    local arr = string.split(levelData.Pos, "|")
    --local pos = Vector3(checknumber(arr[1]),checknumber(arr[2]),0)
    self._spineDp:SetLocalPosition(Vector3(0, 0, 0))
    self._spineDp:SetScale(1)
    local defaultLayer = 5
    local layerOrder = checknumber(self._buildingRef.layer)
    if (layerOrder >= 0) then
        defaultLayer = layerOrder
    end
    self._spineDp:SetRenderOrder(defaultLayer)
    self._spineDp:SetLoadedCallback(function(model)
        self:LoadedCallBack(model)
        --self:SetBuildingAni()
        self:CheckWorkRestState()
        self:SetPeopleNodeList()
        self:LoadInViewSpine()
        self:RefreshInView()
        self:OperateForEating()
    end)
    self._spineDp:Load()


end
--针对餐厅的特殊处理
function LCityBuilding:OperateForEating()

    if(self._buildingRefId == 2005)then
        self._eatingNodeNames = self._eatingNodeNames or {}
        table.dispose(self._eatingNodeNames)
        local trans = self._spineDp:GetDpTrans()
        local childCount = trans.childCount
        for i = 1, childCount do
            local childTrans = trans:GetChild(i - 1)
            if(string.startswith(childTrans.name,"CiR29"))then
                self._eatingNodeNames[childTrans] = 0
                --table.insert(self._eatingNodeNames,childTrans.name)
            end
        end
    end
end
function LCityBuilding:SetEatPeople(nodeName,peopleRefId)
    self._eatingNodeNames[nodeName] = peopleRefId
end
function LCityBuilding:CheckWorkRestState()
    local timeState = CtrlCenter.City:GetCurTimeState()
    if(timeState == 1 or timeState == 3)then
        self:BuildRest()
    else
        self:BuildWork()
    end
    self:LoadInViewSpine()
    self:RefreshInView()
end
function LCityBuilding:SetPeopleNodeList()
    if(checknumber(self._buildingRef.showIn) <= 0)then
        return
    end
    self._peopleNodeList = self._peopleNodeList or {}
    table.dispose(self._peopleNodeList)
    local mainInnerCfg = CtrlCenter.Building:GetInnerMainBuilding(self._buildingRef.type)
    if(mainInnerCfg)then
        for i, v in pairs(mainInnerCfg.peopleSide) do
            local trans = self._spineDp:GetDpTrans():Find(v)
            if(trans)then
                table.insert(self._peopleNodeList,trans)
            end
        end
    end

end
function LCityBuilding:LoadedCallBack(model)
    if (self._cbOk) then
        self._cbOk(self._cbObj, self._buildingRefId)
    end
end
function LCityBuilding:SetBuildingAni()
    if (self._spineDp == nil) then
        return
    end
    if(self._inView)then
        return
    end
    local buildData = ModuleCenter.Building:GetBuildingInfo(self._buildingRefId)
    if (buildData ~= nil) then
        if (checknumber(buildData.endTime) ~= 0) then
            self:PlayAni(_aniEnums.building, true)
            return
        end
    end

    local levelData = self:GetLevelData()
    local play = true
    if(ModuleCenter.Story:IsNewbieRunning())then
        if(CtrlCenter.City:BuildIsInStory(self._buildingRefId))then
            play = false
        end
    end
    if(play)then
        if (levelData.level == 0) then
            self:PlayAni(_aniEnums.ruins, true)
        else
            ---2025.11.10 黄江让去掉特殊处理
            --针对剧情中的渔场做个特殊处理
            --if (ModuleCenter.Story:IsNewbieRunning() and self._buildingRefId == 2004) then
            ----龙蛋，0-1不处理
            --elseif (ModuleCenter.Story:IsNewbieRunning() and self._buildingRefId == 1001 and checknumber(self._oldLevel) == 0) then
            --
            --else
            --    self:PlayAni(_aniEnums.idle1, true)
            --end
            self:PlayAni(_aniEnums.idle1, true)
        end
    end



end
function LCityBuilding:ResetBuildingState(aniName)
    if (self._spineDp == nil) then
        return
    end
    self:PlayAni(aniName, true)
end
function LCityBuilding:ResetBuildingAni()
    if (self._spineDp == nil) then
        return
    end
    local buildData = ModuleCenter.Building:GetBuildingInfo(self._buildingRefId)
    if (buildData ~= nil) then
        if (checknumber(buildData.endTime) ~= 0) then
            self:PlayAni(_aniEnums.building, true)
            return
        end
    end

    local levelData = self:GetLevelData()
    if (levelData.level == 0) then
        self:PlayAni(_aniEnums.ruins, true)
        local buildHud = self._cityView._buildingMgr:GetHUD(self._buildingRefId)
        if buildHud then
            buildHud:SetBuildCreateTipsState(true)
        end
    end
end
function LCityBuilding:ShowPreBuildAni()
    if (self._spineDp == nil) then
        return
    end
    self:PlayAni(_aniEnums.build, true)
    local buildHud = self._cityView._buildingMgr:GetHUD(self._buildingRefId)
    if buildHud then
        buildHud:SetBuildCreateTipsState(false)
    end
end
function LCityBuilding:ShowLevelUpEffect()
    local levelData = self:GetLevelData()
    local t1, t2 = CtrlCenter.Story:CheckTrigger(NewbieTriggerType.BuildUpLevelUp, levelData.refId)
    if (t1 > 0 and t2 > 0) then
        CtrlCenter.Story:StartStory(t2);
        return
    end
    if(self._disPoseTimer)then
        MgrCenter.TimerMgr:RemoveTimer(self._disPoseTimer)
    end
    if (self._levelUpEffectDp ~= nil) then
        self._levelUpEffectDp:Dispose()
        self._levelUpEffectDp = nil
    end
    self._levelUpEffectDp = require("LApp.component.dp.LxEffectDp"):new()
    if (self._buildingRefId == 1001 and levelData.level == 1) then
        self._levelUpEffectDp:InitDp("fx_ui_juqing_longdanfuhua", self._buildingTrans)
        local scale = GameTable.BuildingConfigRef.longTaEffectSize
        local pos = Vector3(checknumber(GameTable.BuildingConfigRef.longTaEffectPosition[1]), checknumber(GameTable.BuildingConfigRef.longTaEffectPosition[2]), 0)
        self._levelUpEffectDp:SetScale(scale)
        self._levelUpEffectDp:SetLocalPosition(pos)
        self._levelUpEffectDp:Load()
        --local pos = Vector3()
    else
        self._levelUpEffectDp:InitDp("fx_ui_juqing_jianzhujiancheng", self._buildingTrans)
        --local levelData = self:GetLevelData()
        local scale = 1
        if (levelData.effectSize > 0) then
            scale = levelData.effectSize
        end
        self._levelUpEffectDp:SetScale(scale)
        self._levelUpEffectDp:SetLocalPosition(Vector3.zero)
        self._levelUpEffectDp:Load()
    end
    self._disPoseTimer = MgrCenter.TimerMgr:DelayTime(function()
        self._levelUpEffectDp:Dispose()
        self._levelUpEffectDp = nil
    end,self,3,false)

end
function LCityBuilding:Load()

end

function LCityBuilding:IsBuildingByGameObject(go)
    if go == self._buildingObj then
        return true
    end
end

function LCityBuilding:ResetEatNode(nodeName)
    self._eatingNodeNames[nodeName] = 0
end
function LCityBuilding:OnUpdate(deltaTime)
    if self._isDisposed then return end
    if(self._dropHudList)then
        for i, v in pairs(self._dropHudList) do
            v:OnUpdate(deltaTime)
        end
    end

end
return LCityBuilding